import React, { useState } from 'react';
import Sidebar from '../components/Dashboard/Sidebar';
import Header from '../components/Dashboard/Header';
import OverviewPanels from '../components/Dashboard/OverviewPanels';
import VisitorTable from '../components/Dashboard/VisitorTable';
import BlacklistTable from '../components/Dashboard/BlacklistTable';
import SecurityMonitoring from '../components/Dashboard/SecurityMonitoring';
import QRCodeManagement from '../components/Dashboard/QRCodeManagement';
import { motion, AnimatePresence } from 'framer-motion';

const Dashboard = () => {
  const [activeTab, setActiveTab] = useState('dashboard');

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard':
        return (
          <motion.div
            initial={{ opacity: 0, scale: 0.98 }}
            animate={{ opacity: 1, scale: 1 }}
            exit={{ opacity: 0 }}
            className="space-y-8"
          >
            <OverviewPanels />

            <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
              <div className="xl:col-span-2 space-y-8">
                <VisitorTable />
                <SecurityMonitoring />
              </div>

              <div className="space-y-8">
                <BlacklistTable />
                <QRCodeManagement />
              </div>
            </div>
          </motion.div>
        );
      case 'approvals':
        return <div className="p-20 text-center"><h2 className="text-3xl font-bold uppercase tracking-widest text-mas-text-dim">Approval Management</h2><p className="mt-4 text-mas-red">Module loading...</p></div>;
      case 'qrcode':
        return <div className="p-8 h-full"><QRCodeManagement /></div>;
      case 'security':
        return <div className="p-8 h-full"><SecurityMonitoring /></div>;
      case 'blacklist':
        return <div className="p-8 h-full"><BlacklistTable /></div>;
      default:
        return (
          <div className="p-20 text-center">
            <h2 className="text-3xl font-bold uppercase tracking-widest text-mas-text-dim">{activeTab.replace('-', ' ')}</h2>
            <p className="mt-4 text-mas-red">This section is currently under development.</p>
          </div>
        );
    }
  };

  return (
    <div className="flex min-h-screen bg-mas-black overflow-x-hidden">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <main className="flex-1 ml-72 flex flex-col min-w-0">
        <Header />

        <div className="flex-1 p-8 bg-[#0D0D0E]">
          <div className="max-w-[1600px] mx-auto">
            <header className="mb-8 flex justify-between items-end">
              <div>
                <h1 className="text-2xl font-black text-white uppercase tracking-[0.15em] leading-none mb-2">
                  System Overview
                </h1>
                <div className="flex items-center gap-3">
                  <div className="w-12 h-[1px] bg-mas-red"></div>
                  <p className="text-[10px] text-mas-text-dim uppercase tracking-[0.3em] font-bold">
                    Real-time Enterprise Intelligence
                  </p>
                </div>
              </div>
              <div className="flex items-center gap-4 text-mas-text-dim">
                <div className="text-right">
                  <p className="text-[9px] uppercase font-bold tracking-widest">Global Server Time</p>
                  <p className="text-xs font-bold text-white tracking-widest leading-none">13:48:22 GMT+5:30</p>
                </div>
              </div>
            </header>

            <AnimatePresence mode="wait">
              <motion.div
                key={activeTab}
                initial={{ opacity: 0, x: 10 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -10 }}
                transition={{ duration: 0.2 }}
              >
                {renderContent()}
              </motion.div>
            </AnimatePresence>
          </div>
        </div>
      </main>
    </div>
  );
};

export default Dashboard;
